SELECT ap.user_id AS id, ap.name, ap.job_number AS jobNumber, ap.department_name AS departmentName, ap.project_group_name AS projectGroupName, su.username, su.password, su.role, su.open_id AS openId, su.status FROM aro_personnel ap LEFT JOIN sys_user su ON su.id = ap.user_id
( ap.user_id LIKE CONCAT('%', #{keyword}, '%') OR ap.name LIKE CONCAT('%', #{keyword}, '%') OR ap.job_number LIKE CONCAT('%', #{keyword}, '%') OR su.username LIKE CONCAT('%', #{keyword}, '%') )
ORDER BY ap.update_time DESC LIMIT #{limit} OFFSET #{offset}

SELECT su.id, su.username, su.password, su.role, su.open_id AS openId, su.status, su.create_time AS createTime, su.display_nickname AS displayNickname, su.mini_bind_type AS miniBindType FROM sys_user su WHERE NOT EXISTS ( SELECT 1 FROM aro_personnel ap WHERE ap.user_id = su.id )
AND ( su.id LIKE CONCAT('%', #{keyword}, '%') OR su.username LIKE CONCAT('%', #{keyword}, '%') OR su.display_nickname LIKE CONCAT('%', #{keyword}, '%') )
ORDER BY su.create_time DESC LIMIT #{limit} OFFSET #{offset}
